import{_ as t,a as o,a3 as r,o as c}from"./chunks/framework.edeurCMZ.js";const h=JSON.parse('{"title":"Roxie Trace Levels Overview","description":"","frontmatter":{},"headers":[],"relativePath":"devdoc/RoxieTraceLevels.md","filePath":"devdoc/RoxieTraceLevels.md","lastUpdated":1782747484000}'),d={name:"devdoc/RoxieTraceLevels.md"};function a(s,e,i,l,n,p){return c(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="roxie-trace-levels-overview" tabindex="-1">Roxie Trace Levels Overview <a class="header-anchor" href="#roxie-trace-levels-overview" aria-label="Permalink to &quot;Roxie Trace Levels Overview&quot;">​</a></h1><p>This document summarizes how <code>traceLevel</code> is used across the <code>roxie</code> directory of the HPCC-Platform repository, as well as miscellaneous trace settings related to specific subsystems.</p><hr><h2 id="table-1-instances-of-tracelevel-and-their-effects" tabindex="-1">Table 1: Instances of <code>traceLevel</code> and Their Effects <a class="header-anchor" href="#table-1-instances-of-tracelevel-and-their-effects" aria-label="Permalink to &quot;Table 1: Instances of `traceLevel` and Their Effects&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Condition/Comparison</th><th>Where Used / Component</th><th>Purpose / Effect</th><th>Example Source/Link</th></tr></thead><tbody><tr><td><code>if (traceLevel)</code></td><td>Roxie main code, listeners, topology managers</td><td>General tracing/logging enabled for most Roxie server events</td><td><a href="https://github.com/hpcc-systems/HPCC-Platform/blob/master/roxie/ccd/ccdlistener.cpp" target="_blank" rel="noreferrer">ccdlistener.cpp</a></td></tr><tr><td><code>traceLevel &gt; 0</code></td><td>Job queue management, worker threads, etc.</td><td>Enables tracing/log messages for workunit or Dali queue actions</td><td><a href="https://github.com/hpcc-systems/HPCC-Platform/blob/master/roxie/ccd/ccdlistener.cpp" target="_blank" rel="noreferrer">ccdlistener.cpp</a></td></tr><tr><td><code>traceLevel &gt; 1</code></td><td>CCDCACHE utility component (not core Roxie)</td><td>More detailed cache warming operations tracing</td><td><a href="https://github.com/hpcc-systems/HPCC-Platform/blob/master/roxie/ccdcache/ccdcache.cpp" target="_blank" rel="noreferrer">ccdcache.cpp</a></td></tr><tr><td><code>traceLevel &gt;= 5</code></td><td>Roxie topology server (toposerver)</td><td>Extra verbosity: receiving requests, sending digests/responses</td><td><a href="https://github.com/hpcc-systems/HPCC-Platform/blob/master/roxie/topo/toposerver.cpp" target="_blank" rel="noreferrer">toposerver.cpp</a></td></tr><tr><td><code>traceLevel &gt;= 6</code></td><td>Roxie topology server (toposerver)</td><td>Very detailed (per-entry) topology trace logs</td><td><a href="https://github.com/hpcc-systems/HPCC-Platform/blob/master/roxie/topo/toposerver.cpp" target="_blank" rel="noreferrer">toposerver.cpp</a></td></tr><tr><td>Default set (eg. <code>1</code>)</td><td>ccdmain.cpp/YAML/configs</td><td>Enables standard trace logging</td><td><a href="https://github.com/hpcc-systems/HPCC-Platform/blob/master/roxie/ccd/ccdmain.cpp" target="_blank" rel="noreferrer">ccdmain.cpp</a></td></tr></tbody></table><hr><h2 id="table-2-miscellaneous-trace-settings-in-roxie" tabindex="-1">Table 2: Miscellaneous Trace Settings in Roxie <a class="header-anchor" href="#table-2-miscellaneous-trace-settings-in-roxie" aria-label="Permalink to &quot;Table 2: Miscellaneous Trace Settings in Roxie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable Name</th><th>Default Value</th><th>Set/Used Where</th><th>Purpose / Effect</th></tr></thead><tbody><tr><td><code>udpTraceLevel</code></td><td><code>1</code></td><td>ccdmain.cpp (<code>@udpTraceLevel</code>)</td><td>UDP networking trace level for Roxie agent/server comms</td></tr><tr><td><code>memTraceLevel</code></td><td><code>1</code></td><td>ccdmain.cpp (<code>@memTraceLevel</code>)</td><td>Memory-related tracing, mainly in roxiemem module</td></tr><tr><td><code>soapTraceLevel</code></td><td><code>1</code></td><td>ccdmain.cpp (<code>@soapTraceLevel</code>)</td><td>SOAP protocol (web service) tracing/logging</td></tr><tr><td><code>miscDebugTraceLevel</code></td><td><code>0</code></td><td>ccdmain.cpp (<code>@miscDebugTraceLevel</code>)</td><td>Extra, miscellaneous debug output (purpose can vary)</td></tr><tr><td><code>udpTraceFlow</code></td><td><code>false</code></td><td>ccdmain.cpp (<code>@udpTraceFlow</code>)</td><td>Boolean: traces per-message UDP network flow</td></tr><tr><td><code>udpTraceTimeouts</code></td><td><code>false</code></td><td>ccdmain.cpp (<code>@udpTraceTimeouts</code>)</td><td>Boolean: traces timeouts on UDP communication</td></tr><tr><td><code>traceRemoteFiles</code></td><td><code>false</code></td><td>ccdmain.cpp (<code>@traceRemoteFiles</code>)</td><td>Boolean: enables tracing for remote file operations</td></tr></tbody></table><hr><p><strong>Notes:</strong></p><ul><li>For <code>traceLevel</code>, the actual effect depends on thresholds tested in various code locations. Nonzero generally enables tracing, higher numbers (5, 6) unlock additional verbosity in specific modules (like toposerver).</li><li>Miscellaneous settings target specific subsystems and may be boolean or integer levels.</li><li>For a comprehensive, current list and default values, check your Roxie configuration and the latest code in <a href="https://github.com/hpcc-systems/HPCC-Platform/blob/master/roxie/ccd/ccdmain.cpp" target="_blank" rel="noreferrer">roxie/ccd/ccdmain.cpp</a>.</li></ul>',11)])])}const u=t(d,[["render",a]]);export{h as __pageData,u as default};
